"""matplotlib.rcsetup — rcParams validation."""


def validate_bool(b):
    if isinstance(b, str):
        return b.lower() in ('true', '1', 'yes', 'on')
    return bool(b)

def validate_float(s):
    return float(s)

def validate_int(s):
    return int(s)

def validate_string(s):
    return str(s)

def validate_color(s):
    return s

def validate_fontsize(s):
    return s

def validate_fontstyle(s):
    return s

def validate_fontweight(s):
    return s

def validate_dpi(s):
    if s == 'figure':
        return s
    return float(s)

def cycler(*args, **kwargs):
    """Simple cycler stub."""
    if args and hasattr(args[0], '__iter__'):
        return list(args[0])
    return [{k: v[i % len(v)] for k, v in kwargs.items()}
            for i in range(max(len(v) for v in kwargs.values()))]


# Default rcParams dict
defaultParams = {}
